import { Command } from "commander";
import { execFileSync, execSync, spawn, spawnSync } from "child_process";
import { createRequire } from "module";
import * as fs from "fs";
import * as path from "path";
import * as os from "os";
import { fileURLToPath } from "url";
import * as p from "@clack/prompts";
import { envExists, runSetupWizard, readEnvFile } from "../wizard/setup.js";
import { logInfo, logError, logDim, logGray, logCyan, COLORS } from "../process/output.js";
import { seedDemoData } from "../seed/demo-data.js";
const require = createRequire(import.meta.url);
const pkg = require("../../package.json");
const __dirname = path.dirname(fileURLToPath(import.meta.url));
const DEFAULT_IMAGE_VERSION = `v${pkg.version}`;
const INCONVO_DIR = path.join(os.homedir(), ".inconvo");
const COMPOSE_FILE = path.join(INCONVO_DIR, "docker-compose.yml");
const INIT_SCRIPT = path.join(INCONVO_DIR, "demo-db-init.sql");
const DATA_DIR = path.join(INCONVO_DIR, "data");
const CREDENTIALS_DIR = path.join(INCONVO_DIR, "credentials");
const SANDBOX_DIR = path.join(INCONVO_DIR, "sandbox");
const SANDBOX_ENV_FILE = path.join(SANDBOX_DIR, ".dev.vars");
const SANDBOX_BASE_URL = "http://host.docker.internal:8787";
const SANDBOX_PORT = "8787";
const WRANGLER_VERSION = "4.61.1";
const OPTIONAL_BIGQUERY_ENV_KEYS = [
    "INCONVO_BIGQUERY_PROJECT_ID",
    "INCONVO_BIGQUERY_DATASET",
    "INCONVO_BIGQUERY_LOCATION",
    "INCONVO_BIGQUERY_KEYFILE",
    "INCONVO_BIGQUERY_CREDENTIALS_JSON",
    "INCONVO_BIGQUERY_CREDENTIALS_BASE64",
    "INCONVO_BIGQUERY_MAX_BYTES_BILLED",
];
// Bundled files (shipped with npm package)
const BUNDLED_COMPOSE_FILE = path.join(__dirname, "..", "..", "docker-compose.yml");
const BUNDLED_INIT_SCRIPT = path.join(__dirname, "..", "..", "demo-db-init.sql");
const BUNDLED_SANDBOX_DIR = path.join(__dirname, "..", "..", "assets", "sandbox");
function checkDockerRunning() {
    try {
        execSync("docker info", { stdio: "pipe" });
        return true;
    }
    catch {
        return false;
    }
}
function checkDockerComposeAvailable() {
    try {
        execSync("docker compose version", { stdio: "pipe" });
        return true;
    }
    catch {
        return false;
    }
}
function generateApiKey() {
    return crypto.randomUUID();
}
/**
 * Rewrite localhost URLs to host.docker.internal for Docker access to host services.
 * This allows users to enter localhost URLs (which the CLI can validate) while
 * Docker containers can still reach host services.
 */
function rewriteLocalhostForDocker(url) {
    return url
        .replace(/localhost/gi, "host.docker.internal")
        .replace(/127\.0\.0\.1/g, "host.docker.internal");
}
function removeBlankOptionalBigQueryEnv(env) {
    for (const key of OPTIONAL_BIGQUERY_ENV_KEYS) {
        const value = env[key];
        if (typeof value === "string" && value.trim().length === 0) {
            delete env[key];
        }
    }
}
/**
 * Open a URL in the system's default browser
 */
function openBrowser(url) {
    const platform = process.platform;
    const cmd = platform === "darwin"
        ? "open"
        : platform === "win32"
            ? "start"
            : "xdg-open";
    try {
        execFileSync(cmd, [url], { stdio: "ignore" });
    }
    catch {
        // Silently fail if browser can't be opened
    }
}
/**
 * Wait for a URL to become available
 */
async function waitForServer(url, maxAttempts = 60) {
    for (let i = 0; i < maxAttempts; i++) {
        try {
            const controller = new AbortController();
            const timeout = setTimeout(() => controller.abort(), 2000);
            const response = await fetch(url, { signal: controller.signal });
            clearTimeout(timeout);
            if (response.ok || response.status < 500) {
                return true;
            }
        }
        catch {
            // Server not ready yet
        }
        await new Promise((resolve) => setTimeout(resolve, 1000));
    }
    return false;
}
/**
 * Wait for the demo database to be ready and seed it with data
 */
async function waitForDemoDbAndSeed(maxAttempts = 60) {
    const connectionString = "postgresql://inconvo:inconvo@localhost:26687/demo";
    // Wait for database to be ready
    for (let i = 0; i < maxAttempts; i++) {
        try {
            await seedDemoData(connectionString);
            return;
        }
        catch {
            // Database not ready yet
        }
        await new Promise((resolve) => setTimeout(resolve, 2000));
    }
    logDim("  Warning: Could not seed demo database");
}
/**
 * Configure the dev-server's SQLite database for demo mode
 * This sets up user context, computed columns, and table conditions
